import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, BookOpen } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminBookForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ Book_ID: '', Title_English: '', Title_Arabic: '', Author: '' });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await AdminService.upsertBook(formData);
      toast.success("Volume Successfully Archived");
      navigate('/admin/books');
    } catch (err) { toast.error("Archival Failed"); }
  };

  const inputStyle = "w-full p-4 rounded-xl bg-gray-50 dark:bg-white/5 dark:text-white font-bold outline-none border border-transparent focus:border-primary transition-all text-xs";

  return (
    <div className="max-w-2xl mx-auto space-y-8 p-12">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-[10px] font-black uppercase text-gray-400">
        <ArrowLeft size={14} /> Back to Library
      </button>
      <div className="bg-white dark:bg-[#0a0a0a] p-12 rounded-[3rem] border dark:border-white/5 shadow-sm">
        <h2 className="text-3xl font-black uppercase italic mb-8 flex items-center gap-4">
          <BookOpen className="text-primary" /> Log <span className="text-primary">Volume</span>
        </h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <input placeholder="Book ID" className={inputStyle} value={formData.Book_ID} onChange={e => setFormData({...formData, Book_ID: e.target.value})} />
          <input placeholder="Title (Eng)" className={inputStyle} value={formData.Title_English} onChange={e => setFormData({...formData, Title_English: e.target.value})} />
          <input placeholder="العنوان بالعربي" dir="rtl" className={inputStyle} value={formData.Title_Arabic} onChange={e => setFormData({...formData, Title_Arabic: e.target.value})} />
          <button className="w-full py-5 bg-black text-white rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-primary transition-all shadow-xl">Commit to Registry</button>
        </form>
      </div>
    </div>
  );
};
